formValidator:
const errors = {};

// Loop through 1 to 8
for (let i = 0; i < 8; i++) {
    const characteristicsKey = `specs__${i}__characteristics`;
    const isRangeKey = `specs__${i}__is_range`;
    const minKey = `specs__${i}__min`;
    const maxKey = `specs__${i}__max`;
    const specificationKey = `specs__${i}__specification`;

    const characteristicsValue = formData[characteristicsKey];
    const isRangeValue = formData[isRangeKey];
    const minValue = formData[minKey];
    const maxValue = formData[maxKey];
    const specificationValue = formData[specificationKey];

    // Only validate if characteristics is provided
    if (characteristicsValue) {

        if (isRangeValue === true) {
            // is_range is true: min and max are required
            if (!minValue && minValue !== 0) {
                errors[minKey] = "Min is required";
            }

            if (!maxValue && maxValue !== 0) {
                errors[maxKey] = "Max is required";
            }

            // Validate min < max
            if (minValue && maxValue) {
                const min = parseFloat(minValue);
                const max = parseFloat(maxValue);

                if (!isNaN(min) && !isNaN(max) && min >= max) {
                    errors[minKey] = "Min must be less than Max";
                }
            }

        } else {
            // is_range is false: specification is required
            if (!specificationValue) {
                errors[specificationKey] = "Specification is required";
            }
        }
    }
}

// Return errors if any, otherwise undefined
return Object.keys(errors).length > 0 ? errors : undefined;
